def generate_pieces(n):
    """
    Generates all possible n-square pieces (polyominoes) up to rotations and reflections.

    Args:
        n: The number of squares in each piece.

    Returns:
        A set of frozensets, where each frozenset represents a unique piece.
        Each coordinate in the frozenset is a tuple (x, y).
    """

    if n <= 0:
        return set()

    if n == 1:
        return {frozenset({(0, 0)})}

    pieces = set()

    def normalize(piece):
        """
        Normalizes a piece by translating it to the origin and sorting the coordinates.
        """
        min_x = min(x for x, y in piece)
        min_y = min(y for x, y in piece)
        return frozenset((x - min_x, y - min_y) for x, y in piece)

    def rotate(piece):
        """
        Rotates a piece 90 degrees clockwise.
        """
        return frozenset((y, -x) for x, y in piece)

    def reflect(piece):
        """
        Reflects a piece across the y-axis.
        """
        return frozenset((-x, y) for x, y in piece)

    def canonicalize(piece):
        """
        Returns the canonical representation of a piece by applying all rotations and reflections
        and choosing the lexicographically smallest representation.
        """
        variants = set()
        variants.add(normalize(piece))
        for _ in range(3):
            piece = rotate(piece)
            variants.add(normalize(piece))
        piece = reflect(piece)
        variants.add(normalize(piece))
        for _ in range(3):
            piece = rotate(piece)
            variants.add(normalize(piece))
        return min(variants)

    def grow_piece(piece):
        """
        Grows a piece by adding a square to each of its neighbors.
        """
        new_pieces = set()
        for x, y in piece:
            neighbors = [(x + 1, y), (x - 1, y), (x, y + 1), (x, y - 1)]
            for nx, ny in neighbors:
                new_piece = piece | {(nx, ny)}
                if len(new_piece) == n:
                    new_pieces.add(canonicalize(new_piece))
        return new_pieces

    # Start with the 1-square piece
    initial_pieces = {frozenset({(0, 0)})}

    # Grow the pieces until they have n squares
    current_pieces = initial_pieces
    for _ in range(1, n):
        next_pieces = set()
        for piece in current_pieces:
            next_pieces |= grow_piece(piece)
        current_pieces = next_pieces

    return current_pieces


