def generate_blokus_pieces(n):
    """
    Generates all possible Blokus pieces of size n, removing symmetries.

    Args:
        n: The number of squares in the piece.

    Returns:
        A set of frozensets, where each frozenset represents a unique Blokus piece.
        Each inner frozenset contains tuples representing the coordinates of the squares in the piece.
    """

    if n <= 0:
        return set()

    if n == 1:
        return {frozenset({(0, 0)})}

    pieces = set()

    def normalize(piece):
        """Normalizes a piece by translating it to the origin."""
        min_x = min(x for x, y in piece)
        min_y = min(y for x, y in piece)
        return frozenset((x - min_x, y - min_y) for x, y in piece)

    def rotate(piece):
        """Rotates a piece 90 degrees clockwise."""
        return frozenset((y, -x) for x, y in piece)

    def reflect(piece):
        """Reflects a piece across the y-axis."""
        return frozenset((-x, y) for x, y in piece)

    def canonicalize(piece):
        """Returns the canonical representation of a piece (smallest after rotations and reflections)."""
        piece = normalize(piece)
        canonical = piece
        for _ in range(3):
            piece = rotate(piece)
            piece = normalize(piece)
            if piece < canonical:
                canonical = piece
        piece = reflect(canonical)
        piece = normalize(piece)
        if piece < canonical:
            canonical = piece
        for _ in range(3):
            piece = rotate(piece)
            piece = normalize(piece)
            if piece < canonical:
                canonical = piece
        return canonical

    def grow_piece(piece, current_size):
        """Recursively grows a piece until it reaches the desired size."""
        nonlocal pieces

        if current_size == n:
            canonical_piece = canonicalize(piece)
            pieces.add(canonical_piece)
            return

        neighbors = set()
        for x, y in piece:
            neighbors.add((x + 1, y))
            neighbors.add((x - 1, y))
            neighbors.add((x, y + 1))
            neighbors.add((x, y - 1))

        for neighbor in neighbors:
            if neighbor not in piece:
                new_piece = piece | {neighbor}
                grow_piece(new_piece, current_size + 1)

    grow_piece(frozenset({(0, 0)}), 1)
    return pieces


