                normalize(rotate(rotate(normalized_piece))),
                normalize(rotate(rotate(rotate(normalized_piece)))),
                normalize(reflect(normalized_piece)),
                normalize(rotate(reflect(normalized_piece))),
                normalize(rotate(rotate(reflect(normalized_piece)))),
                normalize(rotate(rotate(rotate(reflect(normalized_piece))))),
