def generate_pieces(n):
    """
    Generates all possible n-square pieces (polyominoes) up to size n,
    eliminating duplicates due to rotations and reflections.

    Args:
        n: The maximum size of the pieces to generate.

    Returns:
        A dictionary where keys are the number of squares (1 to n) and
        values are lists of sets of coordinates representing the pieces.
    """

    def normalize(piece):
        """
        Normalizes a piece by translating it to the origin and sorting the coordinates.
        """
        min_x = min(x for x, y in piece)
        min_y = min(y for x, y in piece)
        return frozenset((x - min_x, y - min_y) for x, y in piece)

    def rotate(piece):
        """
        Rotates a piece 90 degrees clockwise.
        """
        return frozenset((y, -x) for x, y in piece)

    def reflect(piece):
        """
        Reflects a piece across the x-axis.
        """
        return frozenset((x, -y) for x, y in piece)

    def generate_polyominoes(size):
        """
        Generates all polyominoes of a given size.
        """
        if size == 1:
            return {frozenset([(0, 0)])}

        smaller_polyominoes = generate_polyominoes(size - 1)
        new_polyominoes = set()

        for polyomino in smaller_polyominoes:
            for x, y in polyomino:
                neighbors = [(x + 1, y), (x - 1, y), (x, y + 1), (x, y - 1)]
                for neighbor in neighbors:
                    if neighbor not in polyomino:
                        new_piece = polyomino | {neighbor}
                        new_polyominoes.add(new_piece)

        return new_polyominoes

    def remove_duplicates(pieces):
        """
        Removes duplicate pieces due to rotations and reflections.
        """
        unique_pieces = set()
        for piece in pieces:
            normalized_piece = normalize(piece)
            variants = {
                normalized_piece,
                normalize(rotate(normalized_piece)),
                normalize(rotate(rotate(normalized_piece))),
                normalize(rotate(rotate(rotate(normalized_piece)))),
                normalize(reflect(normalized_piece)),
                normalize(rotate(reflect(normalized_piece))),
                normalize(rotate(rotate(reflect(normalized_piece)))),
                normalize(rotate(rotate(rotate(reflect(normalized_piece))))),
            }
            is_duplicate = False
            for variant in variants:
                if variant in unique_pieces:
                    is_duplicate = True
                    break
            if not is_duplicate:
                unique_pieces.add(normalized_piece)
        return unique_pieces

    results = {}
    for i in range(1, n + 1):
        all_pieces = generate_polyominoes(i)
        unique_pieces = remove_duplicates(all_pieces)
        results[i] = [set(coords) for coords in unique_pieces]

    return results

